---
import type { HTMLTag, Polymorphic } from "astro/types"

import { cn } from "@/lib/utils"

import {
  typographyAStyle,
  typographyBlockquoteStyle,
  typographyH1Style,
  typographyH2Style,
  typographyH3Style,
  typographyH4Style,
  typographyHrStyle,
  typographyInlineCodeStyle,
  typographyLargeStyle,
  typographyLeadStyle,
  typographyListItemStyle,
  typographyListStyle,
  typographyMutedStyle,
  typographyOrderedListStyle,
  typographyPStyle,
  typographyPreStyle,
  typographySmallStyle,
  typographyTableCellStyle,
  typographyTableHeadStyle,
  typographyTableRowStyle,
  typographyTableStyle,
  typographyUnorderedListStyle,
  toArbitrarySelectorClass,
} from "./typography-styles"

type Props<Tag extends HTMLTag> = Polymorphic<{ as: Tag }>

const { as: Tag = "div", class: className, ...props } = Astro.props
---

<Tag
  data-slot="typography"
  class={cn(
    [
      "text-foreground",
      toArbitrarySelectorClass("&>h1", typographyH1Style),
      toArbitrarySelectorClass("&>h2", typographyH2Style),
      toArbitrarySelectorClass("&>h3", typographyH3Style),
      toArbitrarySelectorClass("&>h4", typographyH4Style),
      toArbitrarySelectorClass("&>p", typographyPStyle),
      toArbitrarySelectorClass("&>a", typographyAStyle),
      toArbitrarySelectorClass("&>p>a", typographyAStyle),
      toArbitrarySelectorClass("&>blockquote", typographyBlockquoteStyle),
      toArbitrarySelectorClass("&>blockquote>a", typographyAStyle),
      toArbitrarySelectorClass("&>hr", typographyHrStyle),
      toArbitrarySelectorClass("&>pre", typographyPreStyle),
      toArbitrarySelectorClass("&>ul", typographyListStyle),
      toArbitrarySelectorClass("&>ul", typographyUnorderedListStyle),
      toArbitrarySelectorClass("&>ul>li", typographyListItemStyle),
      toArbitrarySelectorClass("&>ul>li>a", typographyAStyle),
      toArbitrarySelectorClass("&>ol", typographyListStyle),
      toArbitrarySelectorClass("&>ol", typographyOrderedListStyle),
      toArbitrarySelectorClass("&>ol>li", typographyListItemStyle),
      toArbitrarySelectorClass("&>ol>li>a", typographyAStyle),
      "[&>[data-slot=typography-table-container]]:my-6 [&>table]:my-6",
      toArbitrarySelectorClass("&>table", typographyTableStyle),
      toArbitrarySelectorClass("&>table tr", typographyTableRowStyle),
      toArbitrarySelectorClass("&>table th", typographyTableHeadStyle),
      toArbitrarySelectorClass("&>table td", typographyTableCellStyle),
      "[&>table>thead]:border-b [&>table>tbody>tr:last-child]:border-0",
      toArbitrarySelectorClass("&>p:not(pre)>code", typographyInlineCodeStyle),
      toArbitrarySelectorClass("&>.lead", typographyLeadStyle),
      toArbitrarySelectorClass("&>.large", typographyLargeStyle),
      toArbitrarySelectorClass("&>small", typographySmallStyle),
      toArbitrarySelectorClass("&>.muted", typographyMutedStyle),
      "[&>h2:first-child]:mt-0 [&>h2:not(:first-child)]:mt-10",
      "[&>h3:not(:first-child)]:mt-8",
      "[&>h4:not(:first-child)]:mt-8",
      "[&>p:not(:first-child)]:mt-6",
      "[&>blockquote:not(:first-child)]:mt-6",
      "[&>ul]:my-6 [&>ol]:my-6",
      "[&>ul>li+li]:mt-2 [&>ol>li+li]:mt-2",
      "[&>pre]:my-6",
      "[&>[data-slot=typography-large]:not(:first-child)]:mt-6",
    ],
    className
  )}
  {...props}
>
  <slot />
</Tag>

<style is:global>
  [data-slot="typography"] > h1 {
    font-weight: var(--font-weight-extrabold);
  }

  [data-slot="typography"] > h2,
  [data-slot="typography"] > h3,
  [data-slot="typography"] > h4 {
    font-weight: var(--font-weight-semibold);
  }
</style>

<style is:global>
  [data-slot="typography"] > pre.astro-code {
    background: var(--muted) !important;
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 1rem;
    font-size: var(--text-sm);
    line-height: var(--text-sm--line-height);
  }

  [data-slot="typography"] > pre.astro-code code {
    color: inherit !important;
  }

  [data-slot="typography"] :not(pre) > code {
    position: relative;
    border-radius: var(--radius-sm);
    background: var(--muted);
    padding: 0.125rem 0.375rem;
    font-family: var(--font-mono);
    font-size: var(--text-sm);
    font-weight: var(--font-weight-semibold);
  }

  .dark [data-slot="typography"] > pre.astro-code {
    color: var(--shiki-dark, var(--foreground)) !important;
  }

  .dark [data-slot="typography"] > pre.astro-code span[style*="--shiki-dark"] {
    color: var(--shiki-dark) !important;
    font-style: var(--shiki-dark-font-style, inherit) !important;
    font-weight: var(--shiki-dark-font-weight, inherit) !important;
    text-decoration: var(--shiki-dark-text-decoration, inherit) !important;
  }
</style>

export const typographyH1Style =
  "scroll-m-20 text-4xl font-semibold tracking-tight text-balance"

export const typographyH2Style =
  "scroll-m-20 border-b pb-2 text-3xl font-semibold tracking-tight first:mt-0"

export const typographyH3Style =
  "scroll-m-20 text-2xl font-semibold tracking-tight"

export const typographyH4Style =
  "scroll-m-20 text-xl font-semibold tracking-tight"

export const typographyPStyle = "leading-7 [&:not(:first-child)]:mt-6"

export const typographyAStyle = "text-primary underline underline-offset-4"

export const typographyBlockquoteStyle = "mt-6 border-l-2 pl-6 italic"

export const typographyLeadStyle = "text-xl text-muted-foreground"

export const typographyLargeStyle = "text-lg font-semibold"

export const typographySmallStyle = "text-sm leading-none font-medium"

export const typographyMutedStyle = "text-sm text-muted-foreground"

export const typographyInlineCodeStyle =
  "relative rounded bg-muted px-1.5 py-0.5 font-mono text-sm font-semibold"

export const typographyPreStyle =
  "overflow-x-auto rounded-lg border border-border bg-muted p-4 text-sm"

export const typographyListStyle = "ms-6"

export const typographyUnorderedListStyle = "list-disc"

export const typographyOrderedListStyle = "list-decimal"

export const typographyListItemStyle = "mt-2"

export const typographyTableContainerStyle = "my-6 w-full overflow-x-auto"

export const typographyTableStyle = "w-full border-collapse caption-bottom text-sm"

export const typographyTableRowStyle = "border-b border-border transition-colors"

export const typographyTableHeadStyle =
  "text-foreground px-3 py-2 text-left align-middle font-medium"

export const typographyTableCellStyle = "px-3 py-2 align-top text-left"

export const typographyHrStyle = "my-8 border-border"

export function toArbitrarySelectorClass(selector: string, className: string) {
  const normalizedSelector = selector.replaceAll(" ", "_")
  const structuralVariants: Record<string, string> = {
    first: ":first-child",
    last: ":last-child",
    odd: ":nth-child(odd)",
    even: ":nth-child(even)",
  }

  return className
    .split(/\s+/)
    .filter(Boolean)
    .map((token) => {
      const arbitrarySelectorMatch = token.match(/^\[&([^\]]*)\]:(.+)$/)

      if (arbitrarySelectorMatch) {
        const [, nestedSelector, utility] = arbitrarySelectorMatch

        return `[${normalizedSelector}${nestedSelector}]:${utility}`
      }

      const structuralVariantMatch = token.match(
        /^(first|last|odd|even):(.*)$/
      )

      if (structuralVariantMatch) {
        const [, variant, utility] = structuralVariantMatch

        return `[${normalizedSelector}${structuralVariants[variant]}]:${utility}`
      }

      return `[${normalizedSelector}]:${token}`
    })
    .join(" ")
}
